#nullable enable // autogenerated

using MVZ2.GameContent.Bosses;
using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Enemies;
using MVZ2.GameContent.ProgressBars;
using MVZ2.Vanilla.Level;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Level;

namespace MVZ2.GameContent.Stages
{
    [AutoStageDefinition(VanillaStageNames.debug)]
    public partial class DebugStage : StageDefinition
    {
        public DebugStage(string nsp, string name) : base(nsp, name)
        {
            //AddBehaviour(new ConveyorStageBehaviour(this));
        }
        public override void OnStart(LevelEngine level)
        {
            base.OnStart(level);
            ClassicStart(level);
            //ConveyorStart(level);
            level.LevelProgressVisible = true;
            level.SetProgressBarToBoss(VanillaProgressBarID.redDragon);
            level.SetTriggerActive(true);
            level.SetStarshardSlotCount(5);
            var cartRef = level.GetCartReference();
            if (cartRef != null)
                level.SpawnCarts(cartRef, LevelPositions.CART_START_X, 20);

            level.AddBuff(VanillaBuffID.Level.debugEnergy);
            level.AddBuff(VanillaBuffID.Level.debugGodmode);
            level.AddBuff(VanillaBuffID.Level.debugNoRecharge);
            level.AddBuff(VanillaBuffID.Level.debugStarshard);
        }
        public override void OnUpdate(LevelEngine level)
        {
            base.OnUpdate(level);
            level.CheckGameOver();
        }
        private void ClassicStart(LevelEngine level)
        {
            level.SetEnergy(9990);
            level.SetSeedSlotCount(10);
            level.FillSeedPacks(new NamespaceID[]
            {
                VanillaContraptionID.dispenser,
                VanillaContraptionID.tnt,
                VanillaContraptionID.obsidian,
                VanillaContraptionID.gravityPad,
                VanillaContraptionID.forcePad,
                VanillaContraptionID.beacon,
                VanillaContraptionID.skywardBeacon,
                VanillaEnemyID.zombie,
                VanillaEnemyID.ironHelmettedZombie,
                VanillaEnemyID.mesmerizer,
            });
            level.SetArtifactSlotCount(3);
        }
        private void ConveyorStart(LevelEngine level)
        {
            level.SetConveyorSlotCount(10);
            level.AddConveyorSeedPack(VanillaBossID.slenderman);
        }
    }
}
